from PySide6 import QtCore, QtGui, QtWidgets
import re

class SmartHexTextEdit(QtWidgets.QTextEdit):
    """支持hex数据智能换行的文本编辑器"""
    
    def __init__(self, parent=None):
        super().__init__(parent)
        self.setLineWrapMode(QtWidgets.QTextEdit.WidgetWidth)
        self.hex_mode = False
        
    def set_hex_mode(self, enabled):
        """设置是否为hex模式"""
        self.hex_mode = enabled
        
    def insertFromMimeData(self, source):
        text = source.text() if source and source.hasText() else ""
        if not text:
            return
        if self.hex_mode:
            text = self._process_hex_text(text)
        self.textCursor().insertText(text)
            
    def keyPressEvent(self, event):
        """重写按键事件，处理hex模式下的输入"""
        if self.hex_mode and event.key() == QtCore.Qt.Key_Return:
            # 在hex模式下按回车时，检查当前行是否会分割字节
            cursor = self.textCursor()
            current_line = cursor.block().text()
            
            # 如果当前行的hex字符数为奇数，添加一个空格
            hex_chars = re.sub(r'[^0-9A-Fa-f]', '', current_line)
            if len(hex_chars) % 2 == 1:
                cursor.insertText(' ')
                
        super().keyPressEvent(event)
        
    def _process_hex_text(self, text):
        """处理hex文本，确保字节完整性"""
        if not self.hex_mode:
            return text
            
        # 移除所有非hex字符，然后重新格式化
        hex_chars = re.sub(r'[^0-9A-Fa-f]', '', text)
        
        # 每两个字符组成一个字节，用空格分隔
        formatted_hex = ' '.join([hex_chars[i:i+2] for i in range(0, len(hex_chars), 2)])
        
        return formatted_hex


