            # 创建文本框
            edit = QtWidgets.QLineEdit(self.groupBox_customs)
            edit_sizePolicy = QtWidgets.QSizePolicy(QtWidgets.QSizePolicy.Expanding, QtWidgets.QSizePolicy.Minimum)
